    /**
     * @method
     * @name coinsph#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://coins-docs.github.io/rest-api/#klinecandlestick-data
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch (default 500, max 1000)
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] timestamp in ms of the latest candle to fetch
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object interval = this.safeString(this.timeframes, timeframe);
            Object until = this.safeInteger(parameters, "until");
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "interval", interval );
            }};
            if (Helpers.isTrue(Helpers.isEqual(limit, null)))
            {
                limit = 1000;
            }
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "startTime", since);
                // since work properly only when it is "younger" than last "limit" candle
                if (Helpers.isTrue(!Helpers.isEqual(until, null)))
                {
                    Helpers.addElementToObject(request, "endTime", until);
                } else
                {
                    Object duration = Helpers.multiply(this.parseTimeframe(timeframe), 1000);
                    Object endTimeByLimit = this.sum(since, Helpers.multiply(duration, (Helpers.subtract(limit, 1))));
                    Object now = this.milliseconds();
                    Helpers.addElementToObject(request, "endTime", Helpers.mathMin(endTimeByLimit, now));
                }
            } else if (Helpers.isTrue(!Helpers.isEqual(until, null)))
            {
                Helpers.addElementToObject(request, "endTime", until);
                // since work properly only when it is "younger" than last "limit" candle
                Object duration = Helpers.multiply(this.parseTimeframe(timeframe), 1000);
                Helpers.addElementToObject(request, "startTime", Helpers.subtract(until, (Helpers.multiply(duration, (Helpers.subtract(limit, 1))))));
            }
            Helpers.addElementToObject(request, "limit", limit);
            parameters = this.omit(parameters, "until");
            Object response = (this.publicGetOpenapiQuoteV1Klines(this.extend(request, parameters))).join();
            //
            //     [
            //         [
            //             1499040000000,      // Open time
            //             "0.01634790",       // Open
            //             "0.80000000",       // High
            //             "0.01575800",       // Low
            //             "0.01577100",       // Close
            //             "148976.11427815",  // Volume
            //             1499644799999,      // Close time
            //             "2434.19055334",    // Quote asset volume
            //             308,                // Number of trades
            //             "1756.87402397",    // Taker buy base asset volume
            //             "28.46694368"       // Taker buy quote asset volume
            //         ]
            //     ]
            //
            return this.parseOHLCVs(response, market, timeframe, since, limit);
        });

    }

    public Object parseOHLCV(Object ohlcv, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger(ohlcv, 0), this.safeNumber(ohlcv, 1), this.safeNumber(ohlcv, 2), this.safeNumber(ohlcv, 3), this.safeNumber(ohlcv, 4), this.safeNumber(ohlcv, 5)));
    }

