    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades
        //     {
        //         "price": "89685.8",
        //         "id": "1365561108437680129",
        //         "qty": "0.000004",
        //         "quoteQty": "0.000004000000000000", // warning: report to exchange - this is not quote quantity, this is base quantity
        //         "time": "1677523569575",
        //         "isBuyerMaker": false,
        //         "isBestMatch": true
        //     },
        //
        // fetchMyTrades
        //     {
        //         "symbol": "ETHUSDT",
        //         "id": 1375426310524125185,
        //         "orderId": 1375426310415879614,
        //         "price": "1580.91",
        //         "qty": "0.01",
        //         "quoteQty": "15.8091",
        //         "commission": "0",
        //         "commissionAsset": "USDT",
        //         "time": 1678699593307,
        //         "isBuyer": false,
        //         "isMaker":false,
        //         "isBestMatch":false
        //     }
        //
        // createOrder
        //     {
        //         "price": "1579.51",
        //         "qty": "0.001899",
        //         "commission": "0",
        //         "commissionAsset": "ETH",
        //         "tradeId":1375445992035598337
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(trade, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object id = this.safeString2(trade, "id", "tradeId");
        Object orderId = this.safeString(trade, "orderId");
        Object timestamp = this.safeInteger(trade, "time");
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString(trade, "qty");
        Object type = null;
        Object fee = null;
        Object feeCost = this.safeString(trade, "commission");
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            Object feeCurrencyId = this.safeString(trade, "commissionAsset");
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", CoinsphCore.this.safeCurrencyCode(feeCurrencyId) );
            }};
        }
        Object isBuyer = this.safeBool2(trade, "isBuyer", "isBuyerMaker");
        Object side = null;
        if (Helpers.isTrue(!Helpers.isEqual(isBuyer, null)))
        {
            side = ((Helpers.isTrue((Helpers.isEqual(isBuyer, true))))) ? "buy" : "sell";
        }
        Object isMaker = this.safeString(trade, "isMaker");
        Object takerOrMaker = null;
        if (Helpers.isTrue(!Helpers.isEqual(isMaker, null)))
        {
            takerOrMaker = ((Helpers.isTrue((Helpers.isEqual(isMaker, "true"))))) ? "maker" : "taker";
        }
        Object costString = null;
        if (Helpers.isTrue(!Helpers.isEqual(orderId, null)))
        {
            costString = this.safeString(trade, "quoteQty");
        }
        final Object finalOrderId = orderId;
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalCostString = costString;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "order", finalOrderId );
            put( "timestamp", timestamp );
            put( "datetime", CoinsphCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "type", type );
            put( "side", finalSide );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", finalCostString );
            put( "fee", finalFee );
            put( "info", trade );
        }}, market);
    }

