    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // createOrder POST /openapi/v1/order
        //     {
        //         "symbol": "ETHUSDT",
        //         "orderId": 1375445991893797391,
        //         "clientOrderId": "1375445991893799115",
        //         "transactTime": 1678701939513,
        //         "price": "0",
        //         "origQty": "0",
        //         "executedQty": "0.001899",
        //         "cummulativeQuoteQty": "2.99948949",
        //         "status": "FILLED",
        //         "timeInForce": "GTC",
        //         "type": "MARKET",
        //         "side": "BUY",
        //         "stopPrice": "0",
        //         "origQuoteOrderQty": "3",
        //         "fills": [
        //             {
        //                 "price": "1579.51",
        //                 "qty": "0.001899",
        //                 "commission": "0",
        //                 "commissionAsset": "ETH",
        //                 "tradeId":1375445992035598337
        //             }
        //         ]
        //     }
        //
        // fetchOrder GET /openapi/v1/order
        // fetchOpenOrders GET /openapi/v1/openOrders
        // fetchClosedOrders GET /openapi/v1/historyOrders
        // cancelAllOrders DELETE /openapi/v1/openOrders
        //     {
        //         "symbol": "DOGEPHP",
        //         "orderId":1375465375097982423,
        //         "clientOrderId": "1375465375098001241",
        //         "price": "0",
        //         "origQty": "0",
        //         "executedQty": "13",
        //         "cummulativeQuoteQty": "49.621",
        //         "status": "FILLED",
        //         "timeInForce": "GTC",
        //         "type": "MARKET",
        //         "side": "BUY",
        //         "stopPrice": "0",
        //         "time":1678704250171,
        //         "updateTime":1678704250256,
        //         "isWorking":false,
        //         "origQuoteOrderQty": "50"
        //     }
        //
        // cancelOrder DELETE /openapi/v1/order
        //     {
        //         "symbol": "ETHPHP",
        //         "orderId":1375609441915774332,
        //         "clientOrderId": "1375609441915899557",
        //         "price": "96000",
        //         "origQty": "0.001",
        //         "executedQty": "0",
        //         "cummulativeQuoteQty": "0",
        //         "status": "CANCELED",
        //         "timeInForce": "GTC",
        //         "type": "LIMIT",
        //         "side": "SELL",
        //         "stopPrice": "0",
        //         "origQuoteOrderQty": "0"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(order, "orderId");
        Object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        Object timestamp = this.safeInteger2(order, "time", "transactTime");
        Object trades = this.safeValue(order, "fills");
        Object triggerPrice = this.safeString(order, "stopPrice");
        if (Helpers.isTrue(Precise.stringEq(triggerPrice, "0")))
        {
            triggerPrice = null;
        }
        final Object finalMarket = market;
        final Object finalTriggerPrice = triggerPrice;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "clientOrderId", CoinsphCore.this.safeString(order, "clientOrderId") );
            put( "timestamp", timestamp );
            put( "datetime", CoinsphCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "status", CoinsphCore.this.parseOrderStatus(CoinsphCore.this.safeString(order, "status")) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", CoinsphCore.this.parseOrderType(CoinsphCore.this.safeString(order, "type")) );
            put( "timeInForce", CoinsphCore.this.parseOrderTimeInForce(CoinsphCore.this.safeString(order, "timeInForce")) );
            put( "side", CoinsphCore.this.parseOrderSide(CoinsphCore.this.safeString(order, "side")) );
            put( "price", CoinsphCore.this.safeString(order, "price") );
            put( "triggerPrice", finalTriggerPrice );
            put( "average", null );
            put( "amount", CoinsphCore.this.safeString(order, "origQty") );
            put( "cost", CoinsphCore.this.safeString(order, "cummulativeQuoteQty") );
            put( "filled", CoinsphCore.this.safeString(order, "executedQty") );
            put( "remaining", null );
            put( "fee", null );
            put( "fees", null );
            put( "trades", trades );
            put( "info", order );
        }}, market);
    }

